import{_ as t,a as o,a3 as a,o as r}from"./chunks/framework.edeurCMZ.js";const u=JSON.parse('{"title":"HPCC SystemsÂ® Helm Pod Guide","description":"","frontmatter":{},"headers":[],"relativePath":"helm/HPCC_Helm_Pods.md","filePath":"helm/HPCC_Helm_Pods.md","lastUpdated":1782747484000}'),s={name:"helm/HPCC_Helm_Pods.md"};function n(i,e,l,d,p,c){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="hpcc-systemsÂ®-helm-pod-guide" tabindex="-1">HPCC SystemsÂ® Helm Pod Guide <a class="header-anchor" href="#hpcc-systemsÂ®-helm-pod-guide" aria-label="Permalink to &quot;HPCC SystemsÂ® Helm Pod Guide&quot;">â€‹</a></h1><h2 id="overview-of-hpcc-systems-helm-pods" tabindex="-1">Overview of HPCC Systems Helm Pods <a class="header-anchor" href="#overview-of-hpcc-systems-helm-pods" aria-label="Permalink to &quot;Overview of HPCC Systems Helm Pods&quot;">â€‹</a></h2><p>This document describes the pod types created by the HPCC SystemsÂ® Helm chart, what each pod is used for, and how pod naming works.</p><p>The exact set of pods depends on the chart values that are enabled for a deployment. Some components are required for a functional HPCC Systems cluster, while others are optional and are only created when the corresponding feature is enabled.</p><h2 id="scope-of-this-guide" tabindex="-1">Scope of this guide <a class="header-anchor" href="#scope-of-this-guide" aria-label="Permalink to &quot;Scope of this guide&quot;">â€‹</a></h2><p>This guide covers the main workload pods created by the Helm chart under <code>helm/</code>. It focuses on steady-state workload pods and on short-lived job pods that may be created during installation or initialization.</p><p>It does not attempt to describe pods created by unrelated charts or by external Kubernetes add-ons.</p><h2 id="pod-naming-conventions" tabindex="-1">Pod naming conventions <a class="header-anchor" href="#pod-naming-conventions" aria-label="Permalink to &quot;Pod naming conventions&quot;">â€‹</a></h2><p>Pod names are determined by the Kubernetes controller that creates them and by the Helm release name.</p><h3 id="statefulset-pod-names" tabindex="-1">StatefulSet pod names <a class="header-anchor" href="#statefulset-pod-names" aria-label="Permalink to &quot;StatefulSet pod names&quot;">â€‹</a></h3><p>StatefulSets create stable pod names with an ordinal suffix.</p><p>Pattern:</p><p><code>&lt;release-name&gt;-&lt;component-name&gt;-&lt;ordinal&gt;</code></p><p>Examples:</p><ul><li><code>mycluster-dali-0</code></li><li><code>mycluster-thor-1-0</code></li></ul><p>Use this pattern when the pod must keep a stable identity across restarts.</p><h3 id="deployment-pod-names" tabindex="-1">Deployment pod names <a class="header-anchor" href="#deployment-pod-names" aria-label="Permalink to &quot;Deployment pod names&quot;">â€‹</a></h3><p>Deployments create pod names that include a ReplicaSet hash and a random suffix.</p><p>Pattern:</p><p><code>&lt;release-name&gt;-&lt;component-name&gt;-&lt;replicaset-hash&gt;-&lt;pod-suffix&gt;</code></p><p>Example:</p><ul><li><code>mycluster-eclwatch-7c9d8f6d79-q8l2m</code></li></ul><p>Use this pattern when the component is stateless and can be rescheduled freely.</p><h3 id="job-pod-names" tabindex="-1">Job pod names <a class="header-anchor" href="#job-pod-names" aria-label="Permalink to &quot;Job pod names&quot;">â€‹</a></h3><p>Kubernetes Jobs create short-lived pods for one-time work.</p><p>Pattern:</p><p><code>&lt;job-name&gt;-&lt;pod-suffix&gt;</code></p><p>Example:</p><ul><li><code>mycluster-bootstrap-8x7k9</code></li></ul><p>These pods are temporary and are removed after the Job completes, subject to the cluster&#39;s retention settings.</p><h3 id="name-prefix-rules" tabindex="-1">Name prefix rules <a class="header-anchor" href="#name-prefix-rules" aria-label="Permalink to &quot;Name prefix rules&quot;">â€‹</a></h3><p>The leading release prefix comes from the Helm release name unless <code>fullnameOverride</code> or related naming settings change it. If those settings are used, the same pod naming rules still apply, but the prefix changes.</p><h2 id="pod-families-created-by-the-helm-chart" tabindex="-1">Pod families created by the Helm chart <a class="header-anchor" href="#pod-families-created-by-the-helm-chart" aria-label="Permalink to &quot;Pod families created by the Helm chart&quot;">â€‹</a></h2><p>The following sections describe the common pod families created by the chart. The exact list of enabled pods depends on the selected values.</p><table tabindex="0"><thead><tr><th>Component</th><th>Typical pod count</th><th>What the pod is used for</th><th>Required or optional</th></tr></thead><tbody><tr><td>Dali</td><td>1</td><td>Cluster metadata, file system metadata, and coordination services</td><td>Required for a functional cluster</td></tr><tr><td>DFU Server</td><td>1 or more</td><td>File transfer and file management services</td><td>Optional for basic query clusters; required for DFU workflows</td></tr><tr><td>DaFileSrv</td><td>1 or more per enabled instance</td><td>File server support for data access and storage integration</td><td>Optional</td></tr><tr><td>ECL Agent</td><td>1 or more</td><td>Executes ECL workunits and supports distributed processing</td><td>Required when ECL execution is needed</td></tr><tr><td>ECL Compiler</td><td>1 or more</td><td>Compiles ECL code into executable workunits</td><td>Required when compilation happens in-cluster</td></tr><tr><td>ECL Scheduler</td><td>1 or more</td><td>Schedules and coordinates workunit execution</td><td>Optional</td></tr><tr><td>ESP / ECL Watch</td><td>1 or more</td><td>Web user interface and HTTP API endpoints</td><td>Optional for headless clusters; commonly enabled</td></tr><tr><td>ESP service pods</td><td>1 or more per enabled service</td><td>Hosts specific ESP services, such as query or management endpoints</td><td>Optional</td></tr><tr><td>Roxie</td><td>1 or more</td><td>Real-time query serving</td><td>Required for Roxie deployments</td></tr><tr><td>Thor</td><td>1 or more pods per Thor cluster</td><td>Batch processing, query execution, and distributed data processing</td><td>Required for Thor deployments</td></tr><tr><td>Sasha services</td><td>1 or more per enabled service</td><td>Housekeeping, archiving, recovery, and retention tasks</td><td>Optional, but recommended</td></tr><tr><td>Bootstrap or setup Jobs</td><td>Temporary</td><td>One-time installation or initialization tasks</td><td>Optional, depending on chart features</td></tr></tbody></table><h2 id="component-details" tabindex="-1">Component details <a class="header-anchor" href="#component-details" aria-label="Permalink to &quot;Component details&quot;">â€‹</a></h2><h3 id="dali" tabindex="-1">Dali <a class="header-anchor" href="#dali" aria-label="Permalink to &quot;Dali&quot;">â€‹</a></h3><p>Dali is the metadata and coordination service for HPCC Systems. It stores cluster metadata (the System Data Store, or SDS) and supports consistent access to distributed resources.</p><ul><li><strong>Pod type:</strong> StatefulSet.</li><li><strong>Pod count:</strong> One pod per Dali instance.</li><li><strong>Usage:</strong> Metadata management, coordination, and cluster state.</li><li><strong>Requirement level:</strong> Required for a functional cluster.</li></ul><h3 id="dfu-server" tabindex="-1">DFU Server <a class="header-anchor" href="#dfu-server" aria-label="Permalink to &quot;DFU Server&quot;">â€‹</a></h3><p>The DFU Server provides file transfer and file management services (Distributed File Services, or DFS).</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more replicas, depending on the chart values.</li><li><strong>Usage:</strong> Upload, download, and file movement operations.</li><li><strong>Requirement level:</strong> Optional for basic query-only deployments, but required when DFU operations are needed.</li></ul><h3 id="dafilesrv" tabindex="-1">DaFileSrv <a class="header-anchor" href="#dafilesrv" aria-label="Permalink to &quot;DaFileSrv&quot;">â€‹</a></h3><p>DaFileSrv supports file access and storage integration.</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more pods, depending on the enabled storage configuration.</li><li><strong>Usage:</strong> Storage access and file-serving support.</li><li><strong>Requirement level:</strong> Optional.</li></ul><h3 id="ecl-agent" tabindex="-1">ECL Agent <a class="header-anchor" href="#ecl-agent" aria-label="Permalink to &quot;ECL Agent&quot;">â€‹</a></h3><p>The ECL Agent executes ECL workunits.</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more replicas.</li><li><strong>Usage:</strong> Workunit execution and distributed processing support.</li><li><strong>Requirement level:</strong> Required when the cluster runs ECL workloads.</li></ul><h3 id="ecl-compiler" tabindex="-1">ECL Compiler <a class="header-anchor" href="#ecl-compiler" aria-label="Permalink to &quot;ECL Compiler&quot;">â€‹</a></h3><p>The ECL Compiler compiles ECL source into executable workunits.</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more replicas.</li><li><strong>Usage:</strong> Compilation of ECL code.</li><li><strong>Requirement level:</strong> Required when compilation is performed in the cluster.</li></ul><h3 id="ecl-scheduler" tabindex="-1">ECL Scheduler <a class="header-anchor" href="#ecl-scheduler" aria-label="Permalink to &quot;ECL Scheduler&quot;">â€‹</a></h3><p>The ECL Scheduler coordinates workunit scheduling.</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more replicas.</li><li><strong>Usage:</strong> Scheduling and queue management for ECL execution.</li><li><strong>Requirement level:</strong> Optional.</li></ul><h3 id="esp-and-ecl-watch" tabindex="-1">ESP and ECL Watch <a class="header-anchor" href="#esp-and-ecl-watch" aria-label="Permalink to &quot;ESP and ECL Watch&quot;">â€‹</a></h3><p>ESP provides web and API services, including ECL Watch.</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more replicas.</li><li><strong>Usage:</strong> Browser-based management, REST APIs, and user interaction.</li><li><strong>Requirement level:</strong> Optional for automated clusters, but commonly enabled for administration.</li></ul><h3 id="esp-service-pods" tabindex="-1">ESP service pods <a class="header-anchor" href="#esp-service-pods" aria-label="Permalink to &quot;ESP service pods&quot;">â€‹</a></h3><p>Some ESP services are deployed as separate pods.</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more replicas per enabled service.</li><li><strong>Usage:</strong> Specific HTTP or management services, depending on the enabled chart options.</li><li><strong>Requirement level:</strong> Optional.</li></ul><h3 id="roxie" tabindex="-1">Roxie <a class="header-anchor" href="#roxie" aria-label="Permalink to &quot;Roxie&quot;">â€‹</a></h3><p>Roxie provides real-time query serving. It is commonly known as the Rapid Data Delivery Engine.</p><ul><li><strong>Pod type:</strong> Typically a set of workload pods managed by Kubernetes.</li><li><strong>Pod count:</strong> One or more pods per Roxie cluster.</li><li><strong>Usage:</strong> Low-latency query handling.</li><li><strong>Requirement level:</strong> Required for Roxie deployments, optional otherwise.</li><li><strong>Multiple pods:</strong> A Roxie cluster commonly uses multiple pods so queries can be distributed across the cluster.</li></ul><h3 id="thor" tabindex="-1">Thor <a class="header-anchor" href="#thor" aria-label="Permalink to &quot;Thor&quot;">â€‹</a></h3><p>Thor provides batch processing and large-scale distributed query execution. It is commonly known as the Data Factory.</p><ul><li><strong>Pod type:</strong> Typically a set of workload pods managed by Kubernetes.</li><li><strong>Pod count:</strong> One or more pods per Thor cluster.</li><li><strong>Usage:</strong> Batch processing and distributed computation.</li><li><strong>Requirement level:</strong> Required for Thor deployments, optional otherwise.</li><li><strong>Multiple pods:</strong> A Thor cluster usually includes a master pod and one or more worker pods.</li></ul><h3 id="sasha-services" tabindex="-1">Sasha services <a class="header-anchor" href="#sasha-services" aria-label="Permalink to &quot;Sasha services&quot;">â€‹</a></h3><p>Sasha services perform background housekeeping tasks. It is commonly known as Dali&#39;s assistant.</p><ul><li><strong>Pod type:</strong> Usually a Deployment.</li><li><strong>Pod count:</strong> One or more pods per enabled Sasha service.</li><li><strong>Usage:</strong> Archiving, recovery, retention, or related maintenance tasks.</li><li><strong>Requirement level:</strong> Optional, but recommended.</li><li><strong>Multiple pods:</strong> Each enabled Sasha subservice can create its own pod set.</li></ul><h3 id="bootstrap-or-setup-jobs" tabindex="-1">Bootstrap or setup Jobs <a class="header-anchor" href="#bootstrap-or-setup-jobs" aria-label="Permalink to &quot;Bootstrap or setup Jobs&quot;">â€‹</a></h3><p>The chart may create short-lived Jobs for initialization tasks.</p><ul><li><strong>Pod type:</strong> Job.</li><li><strong>Pod count:</strong> Temporary, created only when the Job runs.</li><li><strong>Usage:</strong> Bootstrap, initialization, or other one-time setup work.</li><li><strong>Requirement level:</strong> Optional and feature-dependent.</li></ul><h2 id="required-versus-optional-components" tabindex="-1">Required versus optional components <a class="header-anchor" href="#required-versus-optional-components" aria-label="Permalink to &quot;Required versus optional components&quot;">â€‹</a></h2><p>A component is treated as required in this guide when a normal cluster deployment depends on it for core functionality.</p><p>A component is treated as optional when the chart can be installed without it and the cluster can still function for a narrower use case.</p><p>Examples:</p><ul><li>Dali is required for cluster coordination.</li><li>Roxie is required only when a Roxie serving cluster is deployed.</li><li>Thor is required only when batch processing is deployed.</li><li>ECL Watch is optional for headless deployments, but useful for administration.</li><li>Sasha services are optional background services.</li></ul><h2 id="multiple-pod-components" tabindex="-1">Multiple-pod components <a class="header-anchor" href="#multiple-pod-components" aria-label="Permalink to &quot;Multiple-pod components&quot;">â€‹</a></h2><p>Some components create more than one pod.</p><ul><li><strong>Roxie:</strong> Multiple peer pods, typically one per configured Roxie server.</li><li><strong>Thor:</strong> One master pod plus one or more worker pods.</li><li><strong>ECL Agent, ECL Compiler, DFU Server, ESP, and Sasha services:</strong> May all scale to multiple replicas if the chart values enable that behavior.</li></ul><p>When a component scales out, the pod name pattern depends on the controller type. StatefulSets use stable ordinals, while Deployments use ReplicaSet-generated suffixes.</p><h2 id="practical-summary" tabindex="-1">Practical summary <a class="header-anchor" href="#practical-summary" aria-label="Permalink to &quot;Practical summary&quot;">â€‹</a></h2><p>If you are trying to identify a pod from an HPCC Systems Helm deployment:</p><ol><li>Check whether the pod name ends with an ordinal, such as <code>-0</code> or <code>-1</code>. If it does, the pod is usually managed by a StatefulSet.</li><li>Check whether the pod name includes a ReplicaSet hash and a random suffix. If it does, the pod is usually managed by a Deployment.</li><li>Check whether the pod is short-lived and tied to setup work. If it is, it is probably a Job pod.</li><li>Use the component name in the middle of the pod name to identify the workload, such as <code>dali</code>, <code>thor</code>, <code>roxie</code>, or <code>eclwatch</code>.</li></ol><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">â€‹</a></h2><p>The exact pod set is controlled by the chart values file and by any overrides supplied at install time. If you need a deployment-specific inventory, compare the enabled values against the templates under <code>helm/</code> and the rendered manifests from <code>helm template</code>.</p>',86)])])}const m=t(s,[["render",n]]);export{u as __pageData,m as default};
